rules:
rules_version = '2';

service cloud.firestore {
  match /databases/{database}/documents {

    // Helper function to extract user role from profile document
    function getUserRole() {
      return get(/databases/$(database)/documents/users/$(request.auth.uid)).data.role;
    }

    // 1. Users collection rules
    match /users/{userId} {
      // Any authenticated user can read profiles (e.g. receptionists listing doctors)
      allow read: if request.auth != null;
      // Only admins can register/update staff profiles
      allow write: if request.auth != null && getUserRole() == 'admin';
    }

    // 2. Patients collection rules
    match /patients/{patientId} {
      // Public is allowed to register themselves (create document without authentication)
      allow create: if true;
      // Registered staff members can read all patient files
      allow read: if request.auth != null;
      // Write access is governed by roles
      allow update, delete: if request.auth != null && (
        getUserRole() == 'admin' || 
        getUserRole() == 'receptionist' ||
        (getUserRole() == 'doctor' && resource.data.assignedDoctorId == request.auth.uid)
      );
    }

    // 3. Lab Tests collection rules
    match /labTests/{testId} {
      // Any staff can read, write or update lab tests
      allow read, write: if request.auth != null;
    }

    // 4. Clinical Departments collection rules
    match /departments/{deptId} {
      // Public registration page needs to fetch available departments
      allow read: if true;
      // Only admin can configure departments
      allow write: if request.auth != null && getUserRole() == 'admin';
    }
  }
}
